{"content": "const sharp = require('sharp');

async function makeGreen() {
  const img = sharp('/home/agentuser/.hermes/image_cache/img_d974eea90831.jpg');
  const { data, info } = await img.raw().toBuffer({ resolveWithObject: true });

  const pixels = new Uint8Array(data);

  for (let y = 0; y < info.height; y++) {
    for (let x = 0; x < info.width; x++) {
      const i = (y * info.width + x) * 4;
      const pr = pixels[i], pg = pixels[i+1], pb = pixels[i+2], pa = pixels[i+3];

      // Skip background (warm orange-yellow)
      if (pr > 200 && pg > 160 && pb > 80 && pr - pb > 80) continue;

      if (pa > 200) {
        const avg = (pr + pg + pb) / 3.0;
        pixels[i] = Math.min(255, Math.round(avg * 0.4 + 20));   // R
        pixels[i+1] = Math.min(255, Math.round(avg * 0.8 + 40)); // G
        pixels[i+2] = Math.min(255, Math.round(avg * 0.2 + 10)); // B
      }
    }
  }

  const out = sharp(pixels, { raw: { width: info.width, height: info.height, channels: 4 } });
  await out.png().toFile('/home/agentuser/.hermes/image_cache/green_piggy.png');
  console.log('Done!');
}

makeGreen().catch(console.error);
